INSERT INTO `v1_ba50002facee27f1cdd2955d06f745e5b31937bb95707b850fcf3adf3db15a8c` VALUES (1002, "", "愛情たっぷりのチョコレートケー\nキを完成させよう！\n超キュートなタップゲーム！", "bgm_M199", 1001, "2030/12/31 15:00:00", "bgm_M199_juke", "2020-02-15 15:00:00", "2030/12/31 15:00:00", "お兄ちゃん争奪！\nどっちのチョコがおいしいでSHOW", 10000);
INSERT INTO `v1_ba50002facee27f1cdd2955d06f745e5b31937bb95707b850fcf3adf3db15a8c` VALUES (1003, "", "大回転！クウカ！\n最高のエクスタシーここにあり！\n引っ張って飛ばす、空の旅！", "bgm_M227", 1002, "2030/12/31 15:00:00", "bgm_M227_juke", "2020-02-15 15:00:00", "2030/12/31 15:00:00", "クウカ大回転\n飛行道中エクスタシー", 10000);
INSERT INTO `v1_ba50002facee27f1cdd2955d06f745e5b31937bb95707b850fcf3adf3db15a8c` VALUES (1004, "", "これぞ琉球魂！\n押し寄せるマジムンをなぎ倒す\n爽快アクションゲーム！", "bgm_M249", 1003, "2030/12/31 15:00:00", "bgm_M249_juke", "2020-02-15 15:00:00", "2030/12/31 15:00:00", "カオリのマブイ式空手道場", 10000);
INSERT INTO `v1_ba50002facee27f1cdd2955d06f745e5b31937bb95707b850fcf3adf3db15a8c` VALUES (1005, "", "白熱バトル！\nドラゴンズネスト流\nタイマン式頭脳しりとり！", "bgm_M277", 1004, "2030/12/31 15:00:00", "bgm_M277_juke", "2020-02-15 15:00:00", "2030/12/31 15:00:00", "大激戦！しりとりドラゴンズ", 10000);
INSERT INTO `v1_ba50002facee27f1cdd2955d06f745e5b31937bb95707b850fcf3adf3db15a8c` VALUES (1006, "", "キミはチーズを守り抜けるか！？\n瞬発力が試される\n反射神経系カジュアルゲーム！", "bgm_M355_Lofi", 1005, "2030/12/31 15:00:00", "bgm_M355_Lofi_juke", "2020-05-31 12:00:00", "2030/12/31 15:00:00", "チュウチュウパニック！\nチーズお守り大作戦！", 10000);
INSERT INTO `v1_ba50002facee27f1cdd2955d06f745e5b31937bb95707b850fcf3adf3db15a8c` VALUES (1007, "", "目指せホームランバッター！\nミートタイミングがカギを握る\nスポーツアクションゲーム！", "bgm_M399", 1006, "2030/12/31 15:00:00", "bgm_M399", "2020-08-15 15:00:00", "2030/12/31 15:00:00", "猛訓打撃道！\nミサトのホームランドリル", 10000);
INSERT INTO `v1_ba50002facee27f1cdd2955d06f745e5b31937bb95707b850fcf3adf3db15a8c` VALUES (1008, "", "カルミナファン大興奮！\nライブ応援グッズを手に入れて\n目指せ「カルミナ神推し」！", "bgm_M500", 1007, "2030/12/31 15:00:00", "bgm_M500", "2021-08-31 12:00:00", "2030/12/31 15:00:00", "カルミナサマーライブ\nライブ会場 グッズエリア", 10000);
INSERT INTO `v1_ba50002facee27f1cdd2955d06f745e5b31937bb95707b850fcf3adf3db15a8c` VALUES (1009, "", "レッツ・クッキング！\nミヤコとプリンを作って食べて\nプリンの道を極めよう！", "bgm_M540", 1008, "2030/12/31 15:00:00", "bgm_M540", "2021-12-18 15:00:00", "2030/12/31 15:00:00", "ミヤコ's キッチン　究極への道", 10000);
INSERT INTO `v1_ba50002facee27f1cdd2955d06f745e5b31937bb95707b850fcf3adf3db15a8c` VALUES (1010, "ランドソルクイズコネクト！", "５人チームで力を合わせて多種多\n様なジャンルのクイズに挑戦！\n目指せ、クイズプリンセス！", "bgm_M569", 1009, "2022/02/28 11:59:59", "bgm_M569", "2022-02-15 15:00:00", "2022/02/15 15:00:00", "Happy Anniv.スペシャル　\nランドソルクイズコネクト！", 0);
INSERT INTO `v1_ba50002facee27f1cdd2955d06f745e5b31937bb95707b850fcf3adf3db15a8c` VALUES (1011, "", "砂浜駆けるプリンセス！\nハチャメチャなコースに挑む、\n南の島のビーチフラッグス！", "bgm_M605", 1010, "2030/12/31 15:00:00", "bgm_M605", "2022-07-18 15:00:00", "2030/12/31 15:00:00", "駆けろ常夏！\nアルティメットビーチフラッグス", 10000);
INSERT INTO `v1_ba50002facee27f1cdd2955d06f745e5b31937bb95707b850fcf3adf3db15a8c` VALUES (1012, "放課後クイズエデュケーション　{0}", "めざせ全問正解！\nキャルとスズナと放課後の教室で\n二人きりのクイズ勉強会！", "bgm_MC068", 1012, "2030/12/31 15:00:00", "bgm_MC068", "2023-09-18 15:00:00", "2030/12/31 15:00:00", "キャルとスズナの\n放課後クイズエデュケーション", 10000);
INSERT INTO `v1_ba50002facee27f1cdd2955d06f745e5b31937bb95707b850fcf3adf3db15a8c` VALUES (1013, "行軍（マーチ）A-Go-Go！", "魔物はびこる街道を突き進め！\n【王宮騎士団(NIGHTMARE)】\nの兵たちを率い、訓練に挑戦だ！", "bgm_MC141", 1013, "2030/12/31 15:00:00", "bgm_MC141", "2024-04-18 15:00:00", "2030/12/31 15:00:00", "エリコとマコトの\n行軍（マーチ）A-Go-Go！", 10000);
INSERT INTO `v1_ba50002facee27f1cdd2955d06f745e5b31937bb95707b850fcf3adf3db15a8c` VALUES (1014, "激突！破壊！\nイリーガルタンクウォー", "戦車バトル大会開幕！\n組み上げたオリジナルマシンで\n頂点を目指せ！", "bgm_MC199", 1014, "2030/12/31 15:00:00", "bgm_MC199_Battle", "2024-11-18 15:00:00", "2030/12/31 15:00:00", "激突！破壊！\nイリーガルタンクウォー", 10000);
